const pages = $input.all().map((item) => item.json);

const authFailure = pages.find((page) => page.statusCode === 401 || page.statusCode === 403);
if (authFailure) {
  throw new Error(`05-failed-alert authentication rejected (HTTP ${authFailure.statusCode}); check ucmarket-n8n-service-token`);
}

const unavailable = pages.length === 0 || pages.some((page) =>
  page.error || page.statusCode == null || page.statusCode >= 500
);
if (unavailable) {
  // 連線失敗與後端 5xx 由 01-health-alert 負責；本 workflow 不重複告警，也不更新狀態。
  return [];
}

const unexpected = pages.find((page) => page.statusCode !== 200);
if (unexpected) {
  throw new Error(`05-failed-alert unexpected API status (HTTP ${unexpected.statusCode})`);
}

const orderedPages = [...pages].sort((a, b) => a.body.page - b.body.page);
for (let index = 0; index < orderedPages.length; index++) {
  const body = orderedPages[index].body;
  if (!body || !Array.isArray(body.content) || body.page !== index) {
    throw new Error(`05-failed-alert invalid pagination response at page ${index}`);
  }
  if (index < orderedPages.length - 1 && body.hasNext !== true) {
    throw new Error(`05-failed-alert pagination ended before page ${index + 1}`);
  }
}
if (orderedPages.at(-1).body.hasNext !== false) {
  throw new Error('05-failed-alert pagination did not reach the last page');
}

const jobsById = new Map();
for (const page of orderedPages) {
  for (const job of page.body.content) {
    if (!job?.id || !Number.isInteger(job.attemptCount)) {
      throw new Error('05-failed-alert received an invalid FAILED job');
    }
    const existing = jobsById.get(job.id);
    if (!existing || job.attemptCount > existing.attemptCount) {
      jobsById.set(job.id, job);
    }
  }
}

const staticData = $getWorkflowStaticData('global');
const previous = staticData.alertedAttempts && typeof staticData.alertedAttempts === 'object'
  ? staticData.alertedAttempts
  : {};
const jobs = [...jobsById.values()];
const currentAttempts = Object.fromEntries(
  jobs.map((job) => [job.id, job.attemptCount])
);
const newFailures = jobs
  .filter((job) => previous[job.id] !== job.attemptCount)
  .sort((a, b) => String(b.updatedAt).localeCompare(String(a.updatedAt)));

const detailLimit = 10;
const details = newFailures.slice(0, detailLimit).map((job) =>
  `• ${job.id} | ${job.eventType} | attempt ${job.attemptCount} | ${String(job.updatedAt).replace('T', ' ')}`
);
const omitted = newFailures.length - details.length;
const at = new Date().toLocaleString('zh-TW', { timeZone: 'Asia/Taipei' });
const message = [
  `🚨 UcMarket 通知工作 FAILED：本輪新增 ${newFailures.length} 筆／目前共 ${jobs.length} 筆`,
  ...details,
  ...(omitted > 0 ? [`…另 ${omitted} 筆，請至管理後台查詢`] : []),
  `時間：${at}`,
].join('\n');

return [{
  json: {
    action: newFailures.length > 0 ? 'alert' : 'commit',
    currentAttempts,
    newFailureCount: newFailures.length,
    totalFailed: jobs.length,
    message,
  },
}];

const snapshot = $('Analyze FAILED Snapshot').first().json.currentAttempts;
const staticData = $getWorkflowStaticData('global');
staticData.alertedAttempts = snapshot;
return [];
